import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './Groups.css';

export default function Groups() {
  const { auth, apiHeaders } = useAuth();
  const [dias, setDias] = useState([]);
  const [selectedDia, setSelectedDia] = useState('');
  const [groups, setGroups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [loadingDias, setLoadingDias] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!auth?.uuid) return;
    axios.get(`/api/student/dias/${auth.uuid}`, { headers: apiHeaders })
      .then(r => {
        const sorted = [...(r.data || [])].sort((a, b) => b.anneeAcademiqueId - a.anneeAcademiqueId);
        setDias(sorted);
        if (sorted.length > 0) setSelectedDia(sorted[0].id);
      })
      .catch(() => setError('Impossible de charger les inscriptions.'))
      .finally(() => setLoadingDias(false));
  }, [auth, apiHeaders]);

  useEffect(() => {
    if (!selectedDia) return;
    setLoading(true);
    setError('');
    setGroups([]);
    axios.get(`/api/student/groups/${selectedDia}`, { headers: apiHeaders })
      .then(r => setGroups(r.data || []))
      .catch(e => {
        const status = e.response?.status;
        setError(status === 404 ? 'Aucun groupe disponible pour cette année.' : 'Impossible de charger les groupes.');
      })
      .finally(() => setLoading(false));
  }, [selectedDia, apiHeaders]);

  const selectedDiaObj = dias.find(d => d.id === Number(selectedDia));

  return (
    <div className="groups-page">
      <div className="page-header">
        <h1>Groupes pédagogiques</h1>
        <p className="page-subtitle">Vos groupes par semestre</p>
      </div>

      {!loadingDias && dias.length > 0 && (
        <div className="year-selector card">
          <label htmlFor="dia-select-g">Année académique</label>
          <select
            id="dia-select-g"
            value={selectedDia}
            onChange={e => setSelectedDia(e.target.value)}
          >
            {dias.map(d => (
              <option key={d.id} value={d.id}>
                {d.anneeAcademiqueCode} — {d.niveauLibelleLongLt}
              </option>
            ))}
          </select>
        </div>
      )}

      {selectedDiaObj && (
        <div className="ins-context">
          <span className="chip chip-blue">{selectedDiaObj.ofLlFiliere}</span>
          {selectedDiaObj.ofLlSpecialite && <span className="chip chip-green">{selectedDiaObj.ofLlSpecialite}</span>}
        </div>
      )}

      {loading && <div className="page-loader"><div className="spinner" /></div>}
      {error && <div className="error-banner">{error}</div>}

      {!loading && groups.length > 0 && (
        <div className="groups-grid">
          {groups.map(g => (
            <div key={g.id} className="group-card card">
              <div className="group-icon">👥</div>
              <div className="group-body">
                <h3 className="group-sem">{g.periodeLibelleLongLt}</h3>
                <div className="group-details">
                  <div className="group-detail">
                    <span className="gd-label">Section</span>
                    <span className="gd-value section-badge">{g.nomSection}</span>
                  </div>
                  <div className="group-detail">
                    <span className="gd-label">Groupe TD</span>
                    <span className="gd-value group-badge">G{g.nomGroupePedagogique}</span>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {!loading && !error && groups.length === 0 && selectedDia && (
        <div className="empty-state">
          <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
          <p>Aucun groupe disponible pour cette période</p>
        </div>
      )}
    </div>
  );
}
